import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import Navbar from "./components/Navbar";

function App() {
  // --- ESTADOS ---
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isRegisterMode, setIsRegisterMode] = useState(false); // Para cambiar entre Login y Registro

  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [nuevoRol, setNuevoRol] = useState('vendedor'); // Rol para nuevos usuarios

  const [userRole, setUserRole] = useState('');
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);

  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', categoria: '', stock: 0, precio_compra: 0, precio_venta: 0, fecha_caducidad: '' });

  // --- FUNCIONES DE CARGA (API) ---
  const cargarDatos = async () => {
    try {
      const resStats = await axios.get('http://localhost:5000/api/stats');
      setStats(resStats.data);
      const resProds = await axios.get('http://localhost:5000/api/productos');
      setProductos(resProds.data);
    } catch (e) { console.log("Error de conexión"); }
  };

  // Se usa useEffect para cargar los datos cuando el usuario entra
  useEffect(() => { 
    if (isLoggedIn) cargarDatos(); 
  }, [isLoggedIn]);

  // --- MANEJADORES DE LOGIN Y REGISTRO ---
  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setIsLoggedIn(true);
        setUserRole(res.data.rol);
      }
    } catch (e) { alert("Usuario o contraseña incorrectos"); }
  };

  const handleRegister = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/register', { 
        usuario: usuario, 
        clave: password, 
        rol: nuevoRol 
      });
      if (res.data.success) {
        alert("¡Registro exitoso! Ya puedes iniciar sesión.");
        setIsRegisterMode(false); // Volver al login
      }
    } catch (e) { alert("Error al registrar: El usuario ya existe"); }
  };

  // --- MANEJADORES DE PRODUCTOS ---
  const guardarProducto = async () => {
    try {
      if (editMode) {
        await axios.put(`http://localhost:5000/api/productos/${selectedId}`, nuevoProd);
      } else {
        await axios.post('http://localhost:5000/api/productos', nuevoProd);
      }
      setShowForm(false); setEditMode(false); cargarDatos();
      alert("¡Guardado correctamente!");
    } catch (e) { alert("Error al guardar. Revisa los datos."); }
  };

  const prepararEdicion = (p) => {
    setSelectedId(p.id);
    setNuevoProd({ ...p, fecha_caducidad: p.fecha_caducidad ? p.fecha_caducidad.split('T')[0] : '' });
    setEditMode(true);
    setShowForm(true);
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Borrar producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  // --- 1. VISTA LOGIN / REGISTRO (DISEÑO ORIGINAL + RESPONSIVO) ---
  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card">
          <h2>{isRegisterMode ? 'Crear Cuenta' : 'Iniciar Sesión'}</h2>

          <div className="form-group">
            <label>Usuario:</label>
            <input type="text" placeholder="eduardo" value={usuario} onChange={(e) => setUsuario(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Contraseña:</label>
            <input type="password" placeholder="••••••••" value={password} onChange={(e) => setPassword(e.target.value)} />
          </div>

          {isRegisterMode && (
            <div className="form-group">
              <label>Rol:</label>
              <select 
                style={{width: '100%', padding: '10px', borderRadius: '5px', border: '1px solid #ddd', background: '#ebf2ff'}}
                onChange={(e) => setNuevoRol(e.target.value)}
              >
                <option value="vendedor">Vendedor</option>
                <option value="admin">Administrador</option>
              </select>
            </div>
          )}

          {isRegisterMode ? (
            <>
              <button className="btn-entrar" onClick={handleRegister}>Registrarme</button>
              <p onClick={() => setIsRegisterMode(false)} style={{cursor:'pointer', color:'#2c97ad', marginTop:'15px', fontSize: '14px'}}>
                ¿Ya tienes cuenta? Inicia sesión
              </p>
            </>
          ) : (
            <>
              <button className="btn-entrar" onClick={handleLogin}>Entrar</button>
              <button className="btn-registrar" onClick={() => setIsRegisterMode(true)}>Registrarse</button>
            </>
          )}
        </div>
      </div>
    );
  }

  // --- 2. VISTA DASHBOARD / GESTIÓN (OPTIMIZADO PARA MÓVIL) ---
  return (
    <div className="main-wrapper">
      <header className="header">
        <h1 className="header-title">Mi Tiendita - {view === 'dashboard' ? 'Dashboard' : 'Inventario'}</h1>
        <button className="btn-cerrar" onClick={() => setIsLoggedIn(false)}>Salir</button>
      </header>

      <nav className="nav-bar">
        <span className="nav-link" onClick={() => setView('dashboard')}>Dashboard</span>
        {userRole === 'admin' && <span className="nav-link" onClick={() => setView('gestion')}>Inventario</span>}
      </nav>

      <main className="content-area">
        {view === 'dashboard' ? (
          <div className="dashboard-grid">
            <div className="card clickable" onClick={() => setView('gestion')}>
                <h3>⚠️ Bajo Stock</h3>
                <div className="card-content">{stats.bajo_stock} productos agotándose.</div>
            </div>
            <div className="card">
                <h3>📊 Estadísticas</h3>
                <div className="card-content">
                    <p>Total Productos: {stats.total_productos}</p>
                    <p>Valor Total: ${stats.valor_inventario}</p>
                </div>
            </div>
          </div>
        ) : (
          <div className="card">
            <div className="gestion-header">
                <h3>Listado de Productos</h3>
                <button className="btn-entrar btn-small" onClick={() => { setShowForm(!showForm); setEditMode(false); }}>
                    {showForm ? 'Cancelar' : '+ Agregar'}
                </button>
            </div>

            {showForm && (
              <div className="form-box">
                <input type="text" placeholder="Nombre" value={nuevoProd.nombre} onChange={e=>setNuevoProd({...nuevoProd, nombre:e.target.value})} />
                <input type="number" placeholder="Stock" value={nuevoProd.stock} onChange={e=>setNuevoProd({...nuevoProd, stock:e.target.value})} />
                <input type="number" placeholder="Precio Venta" value={nuevoProd.precio_venta} onChange={e=>setNuevoProd({...nuevoProd, precio_venta:e.target.value})} />
                <button className="btn-entrar" onClick={guardarProducto}>{editMode ? 'Actualizar' : 'Guardar'}</button>
              </div>
            )}

            <div className="table-container">
              <table>
                <thead>
                  <tr><th>Nombre</th><th>Stock</th><th>Precio</th><th>Acciones</th></tr>
                </thead>
                <tbody>
                  {productos.map(p => (
                    <tr key={p.id} className="table-row">
                      <td>{p.nombre}</td>
                      <td>{p.stock}</td>
                      <td>${p.precio_venta}</td>
                      <td>
                        <button className="btn-icon" onClick={() => prepararEdicion(p)}>✏️</button>
                        <button className="btn-icon" onClick={() => eliminar(p.id)}>🗑️</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
